import{_ as a,o as l,c as t,ae as r}from"./chunks/framework.BEtfQoF7.js";const c=JSON.parse('{"title":"Claude Design 시작하기","description":"","frontmatter":{},"headers":[],"relativePath":"claude-design-get-started.md","filePath":"claude-design-get-started.md","lastUpdated":1776682653000}'),i={name:"claude-design-get-started.md"};function o(n,e,s,u,d,h){return l(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="claude-design-시작하기" tabindex="-1">Claude Design 시작하기 <a class="header-anchor" href="#claude-design-시작하기" aria-label="Permalink to &quot;Claude Design 시작하기&quot;">​</a></h1><blockquote><p>외부 참고 문서 번역본, 원문: <a href="https://support.claude.com/en/articles/14604416-get-started-with-claude-design" target="_blank" rel="noreferrer">https://support.claude.com/en/articles/14604416-get-started-with-claude-design</a></p></blockquote><p>Anthropic Labs의 Claude Design은 Claude와 대화하면서 디자인, 상호작용형 프로토타입, 프레젠테이션 등을 만들 수 있게 해줍니다. 이 가이드에서는 첫 프로젝트를 만들고, 디자인을 반복적으로 개선하며, 이 도구를 최대한 활용하는 방법을 단계별로 안내합니다.</p><p>Anthropic Labs의 Claude Design은 현재 Pro, Max, Team, Enterprise 플랜 사용자를 대상으로 연구 미리보기 형태로 제공됩니다. Enterprise 플랜에서는 기본적으로 비활성화되어 있습니다.</p><p>이 가이드는 조직의 디자인 시스템이 이미 설정되어 있다는 전제로 작성되어 있으며, 이 경우 여러분이 만드는 모든 결과물에는 브랜드의 색상, 타이포그래피, 컴포넌트 패턴이 자동으로 적용됩니다. 디자인 시스템 자체를 설정하거나 수정해야 하는 디자인 리드라면 <strong><a href="https://support.claude.com/en/articles/14604397-set-up-your-design-system-in-claude-design" target="_blank" rel="noreferrer">Claude Design에서 디자인 시스템 설정하기</a></strong> 문서를 참고하세요.</p><hr><h2 id="claude-design-작동-방식" tabindex="-1">Claude Design 작동 방식 <a class="header-anchor" href="#claude-design-작동-방식" aria-label="Permalink to &quot;Claude Design 작동 방식&quot;">​</a></h2><p>Claude Design은 크게 두 영역으로 구성되어 있습니다. 왼쪽에는 채팅 인터페이스가, 오른쪽에는 캔버스가 있습니다. 채팅으로 원하는 바를 설명하면 Claude가 캔버스에 실제로 동작하는 디자인을 만들어 줍니다. 이후에는 대화와 인라인 댓글을 통해 원하는 결과가 나올 때까지 반복적으로 다듬을 수 있습니다.</p><p>일반적인 작업 흐름은 다음과 같습니다.</p><ol><li>프로젝트를 생성하고 필요한 컨텍스트(스크린샷, 코드베이스 등)를 추가합니다.</li><li>만들고자 하는 것을 설명합니다.</li><li>Claude가 캔버스에 생성한 결과물을 검토합니다.</li><li>채팅 메시지와 인라인 댓글을 활용해 반복 개선합니다.</li><li>결과가 마음에 들면 내보내거나 공유합니다.</li></ol><hr><h2 id="새-프로젝트-만들기" tabindex="-1">새 프로젝트 만들기 <a class="header-anchor" href="#새-프로젝트-만들기" aria-label="Permalink to &quot;새 프로젝트 만들기&quot;">​</a></h2><p>프로젝트를 생성하면 조직의 디자인 시스템이 자동으로 상속됩니다. 브랜드 에셋을 따로 업로드하거나 설정을 추가로 구성할 필요가 없으며, 브랜드 색상, 폰트, 컴포넌트는 이미 준비되어 있는 상태에서 시작합니다.</p><h3 id="프로젝트에-컨텍스트-추가하기" tabindex="-1">프로젝트에 컨텍스트 추가하기 <a class="header-anchor" href="#프로젝트에-컨텍스트-추가하기" aria-label="Permalink to &quot;프로젝트에 컨텍스트 추가하기&quot;">​</a></h3><p>Claude에게 더 많은 컨텍스트를 제공할수록 더 좋은 결과물을 얻을 수 있습니다. 참고 자료는 프로젝트 진행 중 언제든지 첨부할 수 있습니다.</p><ul><li><strong>스크린샷, 이미지, 기존 에셋:</strong> 기존 디자인, 경쟁 제품, 와이어프레임, 비주얼 레퍼런스 등의 스크린샷을 업로드할 수 있습니다. 재현하고 싶은 디자인 스타일이 담긴 슬라이드 덱이나 문서를 첨부할 수도 있습니다. &quot;이런 느낌으로 만들어 줘&quot;와 같은 요청에 특히 유용합니다.</li><li><strong>코드베이스와 기존 디자인 파일:</strong> 코드 리포지토리를 연결하면 Claude가 기존 컴포넌트, 아키텍처, 스타일링 패턴을 파악할 수 있습니다. 덕분에 처음부터 프로덕션에 가까운 프로토타입을 얻을 수 있습니다. 또한 Import 기능은 기존 제품 디자인 작업물을 다양한 방식으로 업로드하는 것을 지원합니다.</li></ul><h3 id="효과적인-프롬프트-작성하기" tabindex="-1">효과적인 프롬프트 작성하기 <a class="header-anchor" href="#효과적인-프롬프트-작성하기" aria-label="Permalink to &quot;효과적인 프롬프트 작성하기&quot;">​</a></h3><p>좋은 결과를 얻기 위해 디자이너일 필요는 없습니다. 무엇을 만들려고 하는지, 누구를 위한 것인지, 가장 중요한 것이 무엇인지를 구체적으로 전달하세요.</p><p>좋은 프롬프트에는 <strong>목표</strong>(무엇을 만들려는지), <strong>레이아웃</strong>(요소가 어떻게 배치되어야 하는지), <strong>콘텐츠</strong>(어떤 정보를 보여줄지), 그리고 <strong>대상 사용자</strong>(누가 사용할지)가 포함됩니다. 정보가 부족하면 Claude가 추가 질문을 던져 명확히 해 줄 것입니다.</p><p>다음은 효과가 좋은 프롬프트 예시입니다.</p><ul><li>&quot;지역과 제품 라인별 필터가 포함된 월간 매출 대시보드를 만들어 줘.&quot;</li><li>&quot;우리 제품의 핵심 기능을 4개의 화면으로 안내하는 모바일 앱 온보딩 플로우를 디자인해 줘.&quot;</li><li>&quot;히어로 섹션, 코드 예시, 가격 정보가 포함된 새로운 API 제품의 랜딩 페이지를 만들어 줘.&quot;</li><li>&quot;카테고리에 따라 조건부 질문이 노출되는 고객 피드백 수집 폼을 만들어 줘.&quot;</li><li>&quot;콘텐츠 제출물을 검토하고 승인할 수 있는 운영팀 내부 도구를 디자인해 줘.&quot;</li></ul><hr><h2 id="디자인-반복-개선하기" tabindex="-1">디자인 반복 개선하기 <a class="header-anchor" href="#디자인-반복-개선하기" aria-label="Permalink to &quot;디자인 반복 개선하기&quot;">​</a></h2><p>처음 생성된 결과는 출발점일 뿐입니다. 진짜 가치는 반복 수정 과정에서 나옵니다.</p><h3 id="채팅-활용하기" tabindex="-1">채팅 활용하기 <a class="header-anchor" href="#채팅-활용하기" aria-label="Permalink to &quot;채팅 활용하기&quot;">​</a></h3><p>채팅은 디자인 전반에 영향을 주는 큰 범위의 변경에 가장 적합합니다.</p><ul><li>“색상 팔레트를 더 어둡고 미니멀하게 바꿔 줘.”</li><li>“대시보드를 재배치해서 지표는 맨 위 행에, 차트는 그 아래에 놓아 줘.”</li><li>“오른쪽에 설정 패널을 추가해 줘.”</li><li>“이 페이지의 대안 레이아웃을 2~3가지 보여 줘.”</li></ul><p>또한 Claude에게 디자인 결정 이유를 설명하게 하거나, 개선 아이디어를 제안하게 하거나, 접근성 관점에서 디자인을 검토하도록 요청할 수도 있습니다.</p><h3 id="인라인-댓글-활용하기" tabindex="-1">인라인 댓글 활용하기 <a class="header-anchor" href="#인라인-댓글-활용하기" aria-label="Permalink to &quot;인라인 댓글 활용하기&quot;">​</a></h3><p>인라인 댓글은 캔버스의 특정 부분을 직접 클릭해 원하는 변경을 정확히 요청할 수 있는 기능입니다. 위치를 말로 길게 설명하는 것보다 훨씬 빠릅니다.</p><p>좋은 인라인 댓글 예시:</p><ul><li>“이 버튼의 패딩을 더 크게.”</li><li>“이걸 라디오 버튼 대신 드롭다운으로 바꿔 줘.”</li><li>“여기에 기본 브랜드 컬러를 사용해 줘.”</li><li>“이 섹션을 접을 수 있게(collapsible) 만들어 줘.”</li></ul><p><strong>참고:</strong> 댓글이 제대로 반영되지 않는 것 같다면, 해당 피드백을 채팅에 그대로 붙여 넣어 보세요. Claude가 읽기 전에 댓글이 사라지는 간헐적 이슈에 대한 알려진 우회 방법입니다.</p><h3 id="채팅과-댓글-언제-무엇을-써야-할까" tabindex="-1">채팅과 댓글, 언제 무엇을 써야 할까 <a class="header-anchor" href="#채팅과-댓글-언제-무엇을-써야-할까" aria-label="Permalink to &quot;채팅과 댓글, 언제 무엇을 써야 할까&quot;">​</a></h3><p><strong>댓글</strong>은 특정 컴포넌트 단위의 정밀한 변경(&quot;이 버튼 고쳐 줘&quot;, &quot;이 간격 조정해 줘&quot; 등)에 적합합니다. <strong>채팅</strong>은 구조적인 변경, 새로운 섹션 추가, 분위기 또는 스타일 전환, 그 밖에 설명이나 맥락이 필요한 작업에 적합합니다.</p><h2 id="버전과-수정-이력-관리" tabindex="-1">버전과 수정 이력 관리 <a class="header-anchor" href="#버전과-수정-이력-관리" aria-label="Permalink to &quot;버전과 수정 이력 관리&quot;">​</a></h2><p>현재 작업물을 잃지 않으면서 다른 방향을 탐색해 보고 싶다면, Claude에게 이렇게 말해 보세요. “지금까지 한 작업을 저장하고, 완전히 다른 접근을 시도해 봐(Save what we have and try a completely different approach).” Claude는 현재 프로젝트를 저장하고 어디에 저장되었는지 알려 주므로, 대화 중에 이전 버전을 쉽게 참조할 수 있습니다.</p><h2 id="내보내기-export-와-공유" tabindex="-1">내보내기(Export)와 공유 <a class="header-anchor" href="#내보내기-export-와-공유" aria-label="Permalink to &quot;내보내기(Export)와 공유&quot;">​</a></h2><p>디자인이 준비되면 동료들과 공유하거나 다른 곳에서 쓰기 위해 내보낼 수 있습니다. 적절한 포맷은 용도에 따라 다릅니다. 이해관계자 피드백을 받는 경우, 엔지니어링팀에 전달하는 경우, 여러 사람 앞에서 발표하는 경우 등 상황별로 선택이 달라집니다.</p><p>프로젝트를 보고 있을 때 오른쪽 위의 “Export” 버튼을 눌러 다음 형식 중 원하는 내보내기 옵션을 선택하세요.</p><ul><li>.zip 파일로 다운로드</li><li>PDF로 내보내기</li><li>PPTX로 내보내기</li><li>Canva로 보내기</li><li>독립 실행형 HTML로 내보내기</li><li>Claude Code로 전달 <ul><li>로컬 코딩 에이전트로 보내기</li><li>Claude Code Web으로 보내기</li></ul></li></ul><p>또한 공유 가능한 링크를 통해 조직 내부에서 프로젝트를 공유할 수도 있습니다. 공유 옵션으로는 보기 전용(view-only), 댓글(comment), 편집(edit) 권한이 제공됩니다.</p><hr><h2 id="구독-사용량-및-요금제" tabindex="-1">구독 사용량 및 요금제 <a class="header-anchor" href="#구독-사용량-및-요금제" aria-label="Permalink to &quot;구독 사용량 및 요금제&quot;">​</a></h2><p>자세한 내용은 다음 문서를 참고하세요: <strong><a href="https://support.claude.com/en/articles/14667344-claude-design-subscription-usage-and-pricing" target="_blank" rel="noreferrer">Claude Design 구독 사용량 및 요금제</a></strong>.</p><hr><h2 id="최상의-결과를-얻기-위한-팁" tabindex="-1">최상의 결과를 얻기 위한 팁 <a class="header-anchor" href="#최상의-결과를-얻기-위한-팁" aria-label="Permalink to &quot;최상의 결과를 얻기 위한 팁&quot;">​</a></h2><ul><li><strong>단순하게 시작한 뒤 복잡도를 더해 가세요.</strong> 핵심 레이아웃과 콘텐츠부터 먼저 만든 다음, 인터랙션, 예외 케이스, 마무리 다듬기를 순차적으로 추가하세요. Claude는 점진적인 요청에 잘 반응합니다.</li><li><strong>피드백은 구체적으로 하세요.</strong> &quot;뭔가 이상해 보인다&quot;는 실행하기 어렵습니다. &quot;폼 필드 사이의 간격을 8px로 좁혀 주세요&quot;처럼 말하면 Claude가 필요한 지시를 정확히 이해할 수 있습니다.</li><li><strong>디자인 시스템을 참조하세요.</strong> 브랜드의 디자인 시스템에 이미 존재하는 컴포넌트라면 이름으로 호출하세요. 예를 들어 &quot;Primary Button 컴포넌트를 사용해 주세요&quot; 또는 &quot;Card 레이아웃 패턴을 적용해 주세요&quot;처럼요.</li><li><strong>반응형 대응은 일찍부터 고려하세요.</strong> 디자인이 모바일, 태블릿, 데스크톱 모두에서 동작해야 하는지, 아니면 특정 기기에만 해당하는지 미리 말해 주세요.</li><li><strong>변형안을 요청하세요.</strong> 방향이 확실치 않다면 Claude에게 2~3가지 옵션을 보여 달라고 요청하세요. 대안을 비교하는 편이 추측하는 것보다 훨씬 빠릅니다.</li><li><strong>Claude에게 피드백을 요청하세요.</strong> Claude는 접근성, 명도 대비, 정보 위계, 전반적인 사용성 측면에서 디자인을 검토해 줄 수 있습니다. 단순한 생성 도구가 아니라 디자인 협업자로 활용해 보세요.</li></ul><hr><h2 id="알려진-제약-사항" tabindex="-1">알려진 제약 사항 <a class="header-anchor" href="#알려진-제약-사항" aria-label="Permalink to &quot;알려진 제약 사항&quot;">​</a></h2><p>Claude Design은 Anthropic Labs에서 제공하는 실험적 프리뷰 기능입니다. 다음과 같은 사항을 미리 알아 두세요.</p><ul><li><strong>인라인 댓글 유지:</strong> 인라인 댓글이 Claude가 읽기 전에 간헐적으로 사라질 수 있습니다. 이럴 때는 댓글 내용을 채팅창에 직접 붙여 넣어 주세요.</li><li><strong>컴팩트 뷰에서의 저장 오류:</strong> 컴팩트 레이아웃 모드에서 저장 오류가 발생할 수 있습니다. 이 문제가 나타나면 전체(full) 뷰로 전환한 뒤 다시 시도하세요.</li><li><strong>대형 코드베이스:</strong> 매우 큰 저장소를 연결하면 지연이 발생하거나 브라우저에 문제가 생길 수 있습니다. 모노레포 전체 대신 필요한 하위 디렉터리만 연결하는 것을 권장합니다.</li><li><strong>채팅 오류:</strong> &quot;chat upstream error&quot; 메시지가 나타나면 동일한 프로젝트 안에서 새 채팅 탭을 열어 다시 시도해 보세요.</li></ul><hr><h2 id="관련-문서" tabindex="-1">관련 문서 <a class="header-anchor" href="#관련-문서" aria-label="Permalink to &quot;관련 문서&quot;">​</a></h2><ul><li><a href="https://support.claude.com/en/articles/8114491-get-started-with-claude" target="_blank" rel="noreferrer">Claude 시작하기</a></li><li><a href="https://support.claude.com/en/articles/14503590-get-started-with-claude-for-government" target="_blank" rel="noreferrer">Claude for Government 시작하기</a></li><li><a href="https://support.claude.com/en/articles/14552382-your-first-day-in-claude-code" target="_blank" rel="noreferrer">Claude Code에서 보내는 첫날</a></li><li><a href="https://support.claude.com/en/articles/14604397-set-up-your-design-system-in-claude-design" target="_blank" rel="noreferrer">Claude Design에서 디자인 시스템 설정하기</a></li><li><a href="https://support.claude.com/en/articles/14604406-claude-design-admin-guide-for-team-and-enterprise-plans" target="_blank" rel="noreferrer">Team 및 Enterprise 플랜을 위한 Claude Design 관리자 가이드</a></li></ul>',55)])])}const g=a(i,[["render",o]]);export{c as __pageData,g as default};
